index b6a80fef4217..6a09ab978fd9 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -3974,6 +3974,18 @@ static bool isKnownNonEqual(const Value *V1, const Value *V2,
   if (isKnownNonEqualFromContext(V1, V2, Q, Depth))
     return true;

+  // If a non-zero pointer difference is known from context, the pointers are
+  // non-equal.
+  if (match(V1, m_PtrToInt(m_Value(A))) && match(V2, m_PtrToInt(m_Value(B))) &&
+      V1->getType()->isIntegerTy() && V2->getType() == V1->getType()) {
+    const Value *Diff = BinaryOperator::CreateSub(
+        const_cast<Value *>(V1), const_cast<Value *>(V2));
+    if (isKnownNonZero(Diff, Q, Depth + 1))
+      return true;
+  }
+
+  return false;
+
   return false;
 }

@@ -9396,6 +9408,17 @@ isImpliedCondICmps(CmpPredicate LPred, const Value *L0, const Value *L1,
   if (L0 == R0 && L1 == R1)
     return ICmpInst::isImpliedByMatchingCmp(LPred, RPred);

+  // Pointer subtraction is non-zero if the pointers differ.
+  // Take EQ as an example: L0:(ptrtoint x - ptrtoint y) == C and C != 0
+  //                  ==> R0:x == R1:y is false
+  if (ICmpInst::isEquality(LPred) &&
+      match(R0, m_PtrToIntSameSize(DL, m_Specific(L0))) &&
+      match(R1, m_PtrToIntSameSize(DL, m_Specific(L1))) &&
+      match(L0, m_Sub(m_Value(), m_Value())) &&
+      !match(L1, m_ZeroInt()) &&
+      ICmpInst::isImpliedByMatchingCmp(LPred, RPred) == false)
+    return false;
+
   // It only really makes sense in the context of signed comparison for "X - Y
   // must be positive if X >= Y and no overflow".
   // Take SGT as an example:  L0:x > L1:y and C >= 0
@@ -10172,6 +10195,11 @@ void llvm::findValuesAffectedByCondition(
         AddAffected(A);
         if (IsAssume)
           AddAffected(B);
+        if (match(A, m_Sub(m_Value(X), m_Value(B)))) {
+          AddAffected(X);
+          if (IsAssume)
+            AddAffected(B);
+        }
